"use strict";(self.webpackChunkvuepress_theme_hope_template=self.webpackChunkvuepress_theme_hope_template||[]).push([[1401],{29035(a,e,c){c.r(e),c.d(e,{comp:()=>o,data:()=>p});var s=c(78970);const t=c.p+"assets/img/rzjx.b4b2d754.webp",r=c.p+"assets/img/xdd.8b9378a5.webp",d=c.p+"assets/img/xq.3bae07ed.webp",n=c.p+"assets/img/xlx.82d7bb1e.webp",i=c.p+"assets/img/yyjk.78ef50bb.webp",l=c.p+"assets/img/306736ac1e6e53aa0b69c10eab568986.7f7c354b.jpg",m={},o=(0,c(95428).A)(m,[["render",function(a,e){return(0,s.uX)(),(0,s.CE)("div",null,[...e[0]||(e[0]=[(0,s.Fv)('<div class="card-container"><a class="image-card" href="./《认知觉醒》读书笔记.html"><img class="card-img" src="'+t+'" alt="认知觉醒"><div class="card-content"><h3 class="card-title">认知觉醒</h3><p class="card-desc">《认知觉醒》是作者周岭的作品，通过深入浅出的方式揭示了人类思维运作的底层逻辑，帮助我们理解大脑的认知机制，掌握提升学习力、思考力和行动力的有效方法，开启自我改变的觉醒之路。</p></div></a><a class="image-card" href="./《悉达多》读书笔记.html"><img class="card-img" src="'+r+'" alt="悉达多"><div class="card-content"><h3 class="card-title">悉达多</h3><p class="card-desc">《悉达多》是德国作家赫尔曼·黑塞的经典作品，讲述了一位古印度贵族青年寻求生命真谛的修行之旅。通过悉达多的人生经历，探索自我、生命意义与精神觉醒的主题，充满了哲学思考和诗意表达。</p></div></a><a class="image-card" href="./《稀缺》读书笔记.html"><img class="card-img" src="'+d+'" alt="稀缺"><div class="card-content"><h3 class="card-title">稀缺</h3><p class="card-desc">《稀缺》是经济学家塞德希尔·穆来纳森和心理学家埃尔德·沙菲尔合著的作品，深入探讨了&quot;稀缺心态&quot;如何影响我们的思维方式和决策能力。书中揭示了为什么忙碌的人会更忙，贫穷的人会更穷的心理机制。</p></div></a><a class="image-card" href="./《心理学》读书笔记.html"><img class="card-img" src="'+n+'" alt="心理学"><div class="card-content"><h3 class="card-title">心理学</h3><p class="card-desc">这是一本关于心理学基础知识的入门读物，系统介绍了心理学的核心概念、主要流派和研究方法。内容涵盖认知、情绪、人格、发展等多个领域，帮助读者建立对心理学学科的整体认识和理解框架。</p></div></a><a class="image-card" href="./《营养学》读书笔记.html"><img class="card-img" src="'+i+'" alt="营养学"><div class="card-content"><h3 class="card-title">营养学</h3><p class="card-desc">这本营养学读物全面介绍了人体所需的各种营养素、饮食平衡原则以及健康饮食的科学依据。内容涵盖宏量营养素、微量营养素、膳食指南等，帮助读者建立科学的饮食观念，提升健康生活质量。</p></div></a><a class="image-card" href="./《斯坦福大学人生设计课》.html"><img class="card-img" src="'+l+'" alt="营养学"><div class="card-content"><h3 class="card-title">斯坦福大学人生设计课</h3><p class="card-desc">将产品设计思维运用于人生规划。课程目标是“如何运用设计思维，发现自己未来想做什么？”核心定位是用设计思维替代传统人生规划，解决迷茫、焦虑和选择困难。核心理念是：人生不存在完美规划，只有“更适合的人生”。</p></div></a></div>',1)])])}]]),p=JSON.parse('{"path":"/com/read/","title":"我的书单📖","lang":"zh-CN","frontmatter":{"title":"我的书单📖","index":true,"icon":"book-open-reader","toc":false,"order":8,"description":"认知觉醒 认知觉醒 《认知觉醒》是作者周岭的作品，通过深入浅出的方式揭示了人类思维运作的底层逻辑，帮助我们理解大脑的认知机制，掌握提升学习力、思考力和行动力的有效方法，开启自我改变的觉醒之路。 悉达多 悉达多 《悉达多》是德国作家赫尔曼·黑塞的经典作品，讲述了一位古印度贵族青年寻求生命真谛的修行之旅。通过悉达多的人生经历，探索自我、生命意义与精神觉醒的...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"我的书单📖\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-05-18T16:04:09.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"卷卷\\"}]}"],["meta",{"property":"og:url","content":"https://min168.top/com/read/"}],["meta",{"property":"og:site_name","content":"卷卷"}],["meta",{"property":"og:title","content":"我的书单📖"}],["meta",{"property":"og:description","content":"认知觉醒 认知觉醒 《认知觉醒》是作者周岭的作品，通过深入浅出的方式揭示了人类思维运作的底层逻辑，帮助我们理解大脑的认知机制，掌握提升学习力、思考力和行动力的有效方法，开启自我改变的觉醒之路。 悉达多 悉达多 《悉达多》是德国作家赫尔曼·黑塞的经典作品，讲述了一位古印度贵族青年寻求生命真谛的修行之旅。通过悉达多的人生经历，探索自我、生命意义与精神觉醒的..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-05-18T16:04:09.000Z"}],["meta",{"property":"article:modified_time","content":"2026-05-18T16:04:09.000Z"}]]},"git":{"createdTime":1741327523000,"updatedTime":1779120249000,"contributors":[{"name":"youze","username":"youze","email":"youze27@163.com","commits":3,"url":"https://github.com/youze"},{"name":"youze27","username":"youze27","email":"92211723+youze27@users.noreply.github.com","commits":3,"url":"https://github.com/youze27"},{"name":"张有泽","username":"","email":"youze27@163.com","commits":1}]},"readingTime":{"minutes":2.93,"words":878},"filePathRelative":"com/read/README.md","excerpt":"<div class=\\"card-container\\">\\n  <a class=\\"image-card\\" href=\\"./《认知觉醒》读书笔记.html\\">\\n    \\n    <div class=\\"card-content\\">\\n      <h3 class=\\"card-title\\">认知觉醒</h3>\\n      <p class=\\"card-desc\\">《认知觉醒》是作者周岭的作品，通过深入浅出的方式揭示了人类思维运作的底层逻辑，帮助我们理解大脑的认知机制，掌握提升学习力、思考力和行动力的有效方法，开启自我改变的觉醒之路。</p>\\n    </div>\\n  </a>\\n  <a class=\\"image-card\\" href=\\"./《悉达多》读书笔记.html\\">\\n    \\n    <div class=\\"card-content\\">\\n      <h3 class=\\"card-title\\">悉达多</h3>\\n      <p class=\\"card-desc\\">《悉达多》是德国作家赫尔曼·黑塞的经典作品，讲述了一位古印度贵族青年寻求生命真谛的修行之旅。通过悉达多的人生经历，探索自我、生命意义与精神觉醒的主题，充满了哲学思考和诗意表达。</p>\\n    </div>\\n  </a>\\n  <a class=\\"image-card\\" href=\\"./《稀缺》读书笔记.html\\">\\n    \\n    <div class=\\"card-content\\">\\n      <h3 class=\\"card-title\\">稀缺</h3>\\n      <p class=\\"card-desc\\">《稀缺》是经济学家塞德希尔·穆来纳森和心理学家埃尔德·沙菲尔合著的作品，深入探讨了\\"稀缺心态\\"如何影响我们的思维方式和决策能力。书中揭示了为什么忙碌的人会更忙，贫穷的人会更穷的心理机制。</p>\\n    </div>\\n  </a>\\n  <a class=\\"image-card\\" href=\\"./《心理学》读书笔记.html\\">\\n    \\n    <div class=\\"card-content\\">\\n      <h3 class=\\"card-title\\">心理学</h3>\\n      <p class=\\"card-desc\\">这是一本关于心理学基础知识的入门读物，系统介绍了心理学的核心概念、主要流派和研究方法。内容涵盖认知、情绪、人格、发展等多个领域，帮助读者建立对心理学学科的整体认识和理解框架。</p>\\n    </div>\\n  </a>\\n  <a class=\\"image-card\\" href=\\"./《营养学》读书笔记.html\\">\\n    \\n    <div class=\\"card-content\\">\\n      <h3 class=\\"card-title\\">营养学</h3>\\n      <p class=\\"card-desc\\">这本营养学读物全面介绍了人体所需的各种营养素、饮食平衡原则以及健康饮食的科学依据。内容涵盖宏量营养素、微量营养素、膳食指南等，帮助读者建立科学的饮食观念，提升健康生活质量。</p>\\n    </div>\\n  </a>\\n  <a class=\\"image-card\\" href=\\"./《斯坦福大学人生设计课》.html\\">\\n    \\n    <div class=\\"card-content\\">\\n      <h3 class=\\"card-title\\">斯坦福大学人生设计课</h3>\\n      <p class=\\"card-desc\\">将产品设计思维运用于人生规划。课程目标是“如何运用设计思维，发现自己未来想做什么？”核心定位是用设计思维替代传统人生规划，解决迷茫、焦虑和选择困难。核心理念是：人生不存在完美规划，只有“更适合的人生”。</p>\\n    </div>\\n  </a>\\n</div>","autoDesc":true}')}}]);